import { getRes } from '@meli/server-context';

import {
  ACCEPT_CH_HEADER,
  DEVICE_DETECTION_CLIENT_HINTS,
  DEVICE_MODEL_HEADER,
  OS_PLATFORM_NAME_HEADER,
  OS_PLATFORM_VERSION_HEADER,
} from './constants';

/**
 * Add hints to client hints request headers
 * define by device-detection [here](https://github.com/melisource/fury_frontend-device-detection/blob/master/src/client-hints.js#L44).
 */
export function setClientHints() {
  getRes().setHeader(
    ACCEPT_CH_HEADER,
    `${DEVICE_DETECTION_CLIENT_HINTS}, ${OS_PLATFORM_NAME_HEADER}, ${OS_PLATFORM_VERSION_HEADER}, ${DEVICE_MODEL_HEADER}`,
  );
}
